import { ApiError, CollectionMethod } from '@maxio-com/advanced-billing-sdk';
import { getSubscriptionsController } from '../maxioClient.js';
import { centsToNumber } from '../util.js';
import type { CollectionMethodInput, SubscriptionResult } from '../types.js';

/**
 * Typed error thrown by maxioService. Carries an HTTP-ish status code and a
 * human-readable summary so routes can translate it into the `maxio_failed`
 * response shape and post a failure block to Slack.
 */
export class MaxioServiceError extends Error {
  readonly statusCode: number;
  constructor(message: string, statusCode = 502) {
    super(message);
    this.name = 'MaxioServiceError';
    this.statusCode = statusCode;
  }
}

/** Normalize any thrown value (ApiError or otherwise) into a MaxioServiceError. */
function toServiceError(err: unknown, context: string): MaxioServiceError {
  if (err instanceof ApiError) {
    const result = err.result as { errors?: unknown; error?: unknown } | undefined;
    let detail: string | undefined;
    if (result && Array.isArray(result.errors)) {
      detail = result.errors.map((e) => String(e)).join('; ');
    } else if (result && typeof result.error === 'string') {
      detail = result.error;
    } else if (typeof err.body === 'string' && err.body.trim()) {
      detail = err.body.trim();
    }
    const message = detail
      ? `${context}: ${detail} (HTTP ${err.statusCode})`
      : `${context}: Maxio request failed (HTTP ${err.statusCode})`;
    return new MaxioServiceError(message, err.statusCode);
  }
  if (err instanceof Error) {
    return new MaxioServiceError(`${context}: ${err.message}`);
  }
  return new MaxioServiceError(`${context}: ${String(err)}`);
}

const COLLECTION_METHOD: Record<CollectionMethodInput, CollectionMethod> = {
  automatic: CollectionMethod.Automatic,
  remittance: CollectionMethod.Remittance,
};

export interface CreateSubscriptionInput {
  productHandle: string;
  firstName: string;
  lastName: string;
  email: string;
  collectionMethod: CollectionMethodInput;
  couponCode?: string | undefined;
}

/**
 * UC1 — create a subscription. The customer is created inline from the submitted
 * name/email; the email doubles as the customer `reference`, so Maxio reuses an
 * existing customer on a retried submission (idempotent customer). The payment
 * collection method and optional coupon are passed through. Returns plan, MRR,
 * state and the next assessment date read back from the created subscription.
 */
export async function createSubscription(
  input: CreateSubscriptionInput,
): Promise<SubscriptionResult> {
  const client = getMaxioClient();
  try {
    const { result } = await client.subscriptionsController.createSubscription({
      subscription: {
        productHandle: input.productHandle,
        customerAttributes: {
          firstName: input.firstName,
          lastName: input.lastName,
          email: input.email,
          reference: input.email.trim().toLowerCase(),
        },
        paymentCollectionMethod: COLLECTION_METHOD[input.collectionMethod],
        ...(input.couponCode ? { couponCode: input.couponCode } : {}),
      },
    });

    const sub = result.subscription;
    if (!sub || sub.id == null) {
      throw new MaxioServiceError('UC1 createSubscription: Maxio returned no subscription', 502);
    }

    const mrr =
      centsToNumber(sub.productPriceInCents) ?? centsToNumber(sub.product?.priceInCents) ?? 0;

    return {
      subscriptionId: sub.id,
      customerId: sub.customer?.id ?? null,
      state: sub.state ? String(sub.state) : 'unknown',
      productHandle: sub.product?.handle ?? input.productHandle,
      productName: sub.product?.name ?? input.productHandle,
      mrrInCents: mrr,
      currency: 'USD',
      nextAssessmentAt: sub.nextAssessmentAt ?? null,
      currentPeriodEndsAt: sub.currentPeriodEndsAt ?? null,
      couponCode: input.couponCode ?? null,
    };
  } catch (err) {
    if (err instanceof MaxioServiceError) throw err;
    throw toServiceError(err, 'UC1 createSubscription');
  }
}

import { ApiError, IntervalUnit } from '@maxio-com/advanced-billing-sdk';
import { getMaxioClient } from './maxioClient.js';
import { PRODUCT_FAMILY, PLANS } from './constants.js';
import { formatCents } from './util.js';

/**
 * Idempotent seed for UC1 (plan §1.6, §8 Phase 1 — products subset). Ensures the
 * MeterMate product family and the flat recurring `basic` ($99/mo) and `pro`
 * ($299/mo) products exist on the configured Maxio test site, each with an
 * explicit price point. Re-running is safe: existing items are detected and
 * skipped. Metered/event components for later use cases are seeded separately.
 *
 * Run with: npm run seed -w server
 */
async function ensureProductFamily(): Promise<string> {
  const client = getMaxioClient();
  const { result } = await client.productFamiliesController.listProductFamilies({});
  const existing = result.find((r) => r.productFamily?.handle === PRODUCT_FAMILY.handle);
  if (existing?.productFamily?.id != null) {
    console.log(`• Product family '${PRODUCT_FAMILY.handle}' exists (id ${existing.productFamily.id}).`);
    return String(existing.productFamily.id);
  }

  const created = await client.productFamiliesController.createProductFamily({
    productFamily: {
      name: PRODUCT_FAMILY.name,
      description: 'MeterMate consulting plans and usage.',
    },
  });
  const id = created.result.productFamily?.id;
  if (id == null) throw new Error('Failed to create product family: no id returned.');
  console.log(`✓ Created product family '${PRODUCT_FAMILY.handle}' (id ${id}).`);
  return String(id);
}

async function ensureProduct(familyId: string, plan: (typeof PLANS)[number]): Promise<void> {
  const client = getMaxioClient();
  try {
    const { result } = await client.productsController.readProductByHandle(plan.handle);
    if (result.product?.id != null) {
      console.log(`• Product '${plan.handle}' exists (id ${result.product.id}).`);
      return;
    }
  } catch (err) {
    if (!(err instanceof ApiError) || err.statusCode !== 404) throw err;
    // 404 → does not exist yet; fall through to create.
  }

  const created = await client.productsController.createProduct(familyId, {
    product: {
      name: plan.name,
      handle: plan.handle,
      description: plan.description,
      priceInCents: BigInt(plan.priceInCents),
      interval: plan.interval,
      intervalUnit: IntervalUnit.Month,
    },
  });
  console.log(
    `✓ Created product '${plan.handle}' (id ${created.result.product?.id}) at ${formatCents(plan.priceInCents)}/mo.`,
  );
}

async function main(): Promise<void> {
  console.log('Seeding MeterMate products on Maxio test site…\n');
  const familyId = await ensureProductFamily();
  for (const plan of PLANS) {
    await ensureProduct(familyId, plan);
  }
  console.log('\nSeed complete. Plan handles ready: ' + PLANS.map((p) => p.handle).join(', '));
}

main().catch((err: unknown) => {
  if (err instanceof ApiError) {
    console.error(`Seed failed (HTTP ${err.statusCode}):`, err.body || err.result);
  } else {
    console.error('Seed failed:', err instanceof Error ? err.message : err);
  }
  process.exitCode = 1;
});

