import { getProductFamiliesController, getComponentsController } from '../maxioClient.js';
import { PRODUCT_FAMILY } from '../constants.js';
import type { ComponentInfo } from '../types.js';

/**
 * Live catalog cache (plan risk mitigation §11): resolves the MeterMate product
 * family id and the `handle → component` map once, then serves from memory so
 * usage recording can dispatch on the cached component kind without a lookup per
 * request. Loaded lazily on first use; `refresh()` clears it. Any Maxio error
 * during load propagates to the caller (caught and normalized by maxioService).
 */
let familyId: number | null = null;
let components: Map<string, ComponentInfo> | null = null;
let loading: Promise<void> | null = null;

async function resolveFamilyId(): Promise<number> {
  if (familyId != null) return familyId;
  const { result } = await getProductFamiliesController().listProductFamilies({});
  const match = result.find((r) => r.productFamily?.handle === PRODUCT_FAMILY.handle);
  if (match?.productFamily?.id == null) {
    throw new Error(
      `Product family '${PRODUCT_FAMILY.handle}' not found on the Maxio site. Run the seed first.`,
    );
  }
  familyId = match.productFamily.id;
  return familyId;
}

async function loadComponents(): Promise<void> {
  const id = await resolveFamilyId();
  const { result } = await getComponentsController().listComponentsForProductFamily({
    productFamilyId: id,
  });
  const map = new Map<string, ComponentInfo>();
  for (const wrapper of result) {
    const c = wrapper.component;
    if (c?.id != null && c.handle) {
      map.set(c.handle, {
        id: c.id,
        handle: c.handle,
        name: c.name ?? c.handle,
        kind: c.kind ? String(c.kind) : 'unknown',
      });
    }
  }
  components = map;
}

async function ensureLoaded(): Promise<void> {
  if (components) return;
  if (!loading) {
    loading = loadComponents().finally(() => {
      loading = null;
    });
  }
  await loading;
}

/** Resolve a component by handle from the live catalog, or null if absent. */
export async function getComponent(handle: string): Promise<ComponentInfo | null> {
  await ensureLoaded();
  return components?.get(handle) ?? null;
}

/** Clear the cache so the next lookup reloads from Maxio (e.g. after seeding). */
export function refreshCatalog(): void {
  familyId = null;
  components = null;
}

