export interface RecordUsageInput {
  subscriptionId: number;
  componentHandle: string;
  quantity: number;
  memo?: string | undefined;
  timestamp?: string | undefined;
}

/** Component kinds whose usage is recorded as a quantity via createUsage. */
const QUANTITY_KINDS = new Set([
  'metered_component',
  'quantity_based_component',
  'prepaid_usage_component',
]);

/**
 * UC2 — record usage against a component. Dispatches on the cached component
 * kind: quantity-style components record a usage quantity (+ optional memo) and
 * the running period total is read back from usage history; event-based
 * components record a usage event (+ optional timestamp) via the EBB ingestion
 * method. Rated usage accrues to the next invoice.
 */
export async function recordUsage(input: RecordUsageInput): Promise<UsageResult> {
  try {
    const component = await getComponent(input.componentHandle);
    if (!component) {
      const known = findComponentMeta(input.componentHandle);
      const hint = known && !known.seedable
        ? ` (the '${known.handle}' event-based component requires an EBB metric configured in the Maxio UI)`
        : '';
      throw new MaxioServiceError(
        `UC2 recordUsage: component '${input.componentHandle}' was not found in the catalog${hint}.`,
        404,
      );
    }
    const meta = findComponentMeta(input.componentHandle);
    const unitName = meta?.unitName ?? component.name;

    // Event-based path — record an event (timestamp optional).
    if (component.kind === 'event_based_component') {
      const sc = getSubscriptionComponentsController();
      await sc.recordEvent(component.handle, undefined, {
        chargify: {
          subscriptionId: input.subscriptionId,
          ...(input.timestamp ? { timestamp: input.timestamp } : {}),
        },
      });
      return {
        componentHandle: component.handle,
        componentName: component.name,
        recordedAs: 'event',
        quantity: input.quantity,
        periodTotal: null,
        unitName,
        memo: input.memo ?? null,
        accruesToNextInvoice: true,
      };
    }

    // Quantity-style path — record a usage quantity, then read the period total.
    if (!QUANTITY_KINDS.has(component.kind)) {
      throw new MaxioServiceError(
        `UC2 recordUsage: component '${component.handle}' has kind '${component.kind}', which does not accept usage.`,
        422,
      );
    }

    const sc = getSubscriptionComponentsController();
    await sc.createUsage(input.subscriptionId, component.id, {
      usage: {
        quantity: input.quantity,
        ...(input.memo ? { memo: input.memo } : {}),
      },
    });

    const periodTotal = await readPeriodTotal(input.subscriptionId, component.id);

    return {
      componentHandle: component.handle,
      componentName: component.name,
      recordedAs: 'metered',
      quantity: input.quantity,
      periodTotal,
      unitName,
      memo: input.memo ?? null,
      accruesToNextInvoice: true,
    };
  } catch (err) {
    if (err instanceof MaxioServiceError) throw err;
    throw toServiceError(err, 'UC2 recordUsage');
  }
}

/** Sum recorded usage quantities for a component (best-effort period total). */
async function readPeriodTotal(subscriptionId: number, componentId: number): Promise<number | null> {
  try {
    const { result } = await getSubscriptionComponentsController().listUsages({
      subscriptionIdOrReference: subscriptionId,
      componentId,
      perPage: 200,
      page: 1,
    });
    return result.reduce((sum, u) => {
      const q = u.usage?.quantity;
      const n = typeof q === 'string' ? Number(q) : (q ?? 0);
      return sum + (Number.isFinite(n) ? n : 0);
    }, 0);
  } catch {
    // Period total is informational; never fail the recording over it.
    return null;
  }
}

