 * Ensure the metered usage components exist. Only `seedable` (metered/per-unit)
 * components are created via the SDK; event-based components require an EBB
 * metric created in the Maxio UI and are skipped with a clear notice.
 */
async function ensureComponents(familyId: string): Promise<void> {
  const components = getComponentsController();
  const { result } = await components.listComponentsForProductFamily({
    productFamilyId: Number(familyId),
  });
  const existingHandles = new Set(
    result.map((r) => r.component?.handle).filter((h): h is string => Boolean(h)),
  );

  for (const comp of COMPONENTS) {
    if (!comp.seedable) {
      console.log(
        `• Skipping '${comp.handle}' (event-based — create its EBB metric in the Maxio UI to enable usage events).`,
      );
      continue;
    }
    if (existingHandles.has(comp.handle)) {
      console.log(`• Component '${comp.handle}' exists.`);
      continue;
    }
    const created = await components.createMeteredComponent(familyId, {
      meteredComponent: {
        name: comp.name,
        unitName: comp.unitName,
        handle: comp.handle,
        pricingScheme: PricingScheme.PerUnit,
        taxable: false,
        unitPrice: comp.unitPrice,
      },
    });
    console.log(
      `✓ Created metered component '${comp.handle}' (id ${created.result.component?.id}) at $${comp.unitPrice}/${comp.unitName}.`,
    );
  }
}

