      // Belt-and-suspenders: treat a uniqueness 422 as "already exists".
      if (err instanceof ApiError && err.statusCode === 422) {
        console.log(`• Component '${comp.handle}' already exists (create rejected as duplicate).`);
        continue;
      }
      throw err;
    }
  }
}

