import { ApiError } from '@maxio-com/advanced-billing-sdk';
import { getComponentsController } from '../maxioClient.js';
import type { ComponentInfo } from '../types.js';

/**
 * Live catalog cache (plan risk mitigation §11). Resolves components by handle
 * via `findComponent` — which is site-wide and not subject to product-family
 * pagination — and memoizes the result (including "not found") so usage
 * recording can dispatch on the cached component kind without a lookup per
 * request. `refreshCatalog()` clears the cache (e.g. after seeding). Maxio errors
 * other than 404 propagate to the caller (normalized by maxioService).
 */
const cache = new Map<string, ComponentInfo | null>();

/** Resolve a component by handle from the live catalog, or null if absent. */
export async function getComponent(handle: string): Promise<ComponentInfo | null> {
  if (cache.has(handle)) return cache.get(handle) ?? null;

  try {
    const { result } = await getComponentsController().findComponent(handle);
    const c = result.component;
    if (c?.id == null || !c.handle) {
      cache.set(handle, null);
      return null;
    }
    const info: ComponentInfo = {
      id: c.id,
      handle: c.handle,
      name: c.name ?? c.handle,
      kind: c.kind ? String(c.kind) : 'unknown',
    };
    cache.set(handle, info);
    return info;
  } catch (err) {
    if (err instanceof ApiError && err.statusCode === 404) {
      cache.set(handle, null);
      return null;
    }
    throw err;
  }
}

/** Clear the cache so the next lookup reloads from Maxio (e.g. after seeding). */
export function refreshCatalog(): void {
  cache.clear();
}

