import { getSubscriptionsController, getSubscriptionComponentsController } from './maxioClient.js';

/** Throwaway diagnostic: inspect a subscription's product family and components. */
async function main(): Promise<void> {
  const subId = 92665720;
  const subs = getSubscriptionsController();
  const sc = getSubscriptionComponentsController();

  const { result } = await subs.readSubscription(subId);
  const sub = result.subscription;
  console.log('Subscription', subId, {
    state: sub?.state,
    productHandle: sub?.product?.handle,
    productFamilyId: sub?.product?.productFamily?.id,
    productFamilyHandle: sub?.product?.productFamily?.handle,
  });

  const list = await sc.listSubscriptionComponents({ subscriptionId: subId });
  console.log('\nComponents on subscription:');
  for (const item of list.result) {
    console.log('-', {
      componentId: item.componentId,
      handle: item.componentHandle,
      name: item.name,
      kind: item.kind,
      enabled: item.enabled,
    });
  }
}

main().catch((err: unknown) => {
  console.error('diag failed:', err);
  process.exitCode = 1;
});

