      const created = await components.createMeteredComponent(familyId, {
        meteredComponent: {
          name: comp.name,
          unitName: comp.unitName,
          handle: comp.handle,
          pricingScheme: PricingScheme.PerUnit,
          taxable: false,
          unitPrice: comp.unitPrice,
