      windowDays,
      subscriptionsConsidered: subs.size,
      activeCount,
      mrrInCents,
      newSignups,
      churn,
      overdueInvoices,
      recentEvents,
      caveat: DIGEST_CAVEAT,
    };
  } catch (err) {
    if (err instanceof MaxioServiceError) throw err;
    throw toServiceError(err, 'UC6 buildDigest');
  }
}

